31	const PROCESSING_FEE = 5;
32	const BLOCK_OF_THREE_PREMIUM = 60;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const FIRST_INSURANCE_RATE = 0.1;
35	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
