40	function enchantmentLevel(item: Item): number {
41	  return item.enchantment ?? 0;
42	}
43	
44	function surchargeRateFor(item: Item): number {
45	  let rate = 0;
46	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
47	  if (enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
48	  return rate;
49	}
50	
51	function surchargeFor(item: Item): number {
52	  return basePremiumByType[item.type] * surchargeRateFor(item);
53	}
54	
55	function premiumForTypeBlock(type: string, count: number): number {
56	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
57	  return count * basePremiumByType[type];
58	}
