60	export function quote(
61	  customer: Customer,
62	  items: Item[],
63	  options: QuoteOptions = {},
64	): QuoteResult {
65	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
66	    counts[item.type] = (counts[item.type] ?? 0) + 1;
67	    return counts;
68	  }, {});
69	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
70	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
71	    0,
72	  );
73	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
74	  const basePremium = baseWithoutSurcharges + surcharges;
75	
76	  let premium = basePremium;
77	  if (customer.yearsWithMHPCO >= 2) premium -= baseWithoutSurcharges * LOYALTY_DISCOUNT_RATE;
78	  premium += baseWithoutSurcharges * FIRST_INSURANCE_RATE;
79	  if (options.followUp) premium -= baseWithoutSurcharges * FOLLOW_UP_DISCOUNT_RATE;
80	  premium = Math.ceil(premium + PROCESSING_FEE);
81	
82	  return { basePremium, premium, items };
83	}
