109	const CAP_MULTIPLIER = 2;
110	const DEDUCTIBLE = 100;
111	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
112	const HALF_REIMBURSEMENT_RATE = 0.5;
113	
114	function totalInsuranceValue(policy: QuoteResult): number {
115	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
116	}
117	
118	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
119	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
120	  const halfReimbursementApplies =
121	    damagedItem !== undefined &&
122	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
123	  const reimbursed = halfReimbursementApplies
124	    ? damage.amount * HALF_REIMBURSEMENT_RATE
125	    : damage.amount;
126	  return reimbursed - DEDUCTIBLE;
127	}
128	
129	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
130	  const totalPayout = incident.damages.reduce(
131	    (total, damage) => total + payoutForDamage(damage, policy),
132	    0,
133	  );
134	  const payout = Math.floor(totalPayout);
135	  const payoutCap = CAP_MULTIPLIER * totalInsuranceValue(policy);
136	  return { payout, remainingCap: payoutCap - payout };
137	}
